package com.eventplatform.producer;

import com.eventplatform.model.Event;
import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.SendResult;
import org.springframework.stereotype.Service;

import java.util.concurrent.CompletableFuture;

@Service
public class EventProducer {

    private static final Logger logger = LoggerFactory.getLogger(EventProducer.class);
    private static final String EVENTS_TOPIC = "events-topic";
    private static final String NOTIFICATIONS_TOPIC = "notifications-topic";
    private static final String AUDIT_TOPIC = "audit-topic";

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final ObjectMapper objectMapper;

    public EventProducer(KafkaTemplate<String, String> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
        this.objectMapper = new ObjectMapper();
        this.objectMapper.registerModule(new JavaTimeModule());
    }

    public void publishEvent(Event event) {
        try {
            String eventJson = objectMapper.writeValueAsString(event);
            CompletableFuture<SendResult<String, String>> future =
                    kafkaTemplate.send(EVENTS_TOPIC, event.getId(), eventJson);

            future.whenComplete((result, ex) -> {
                if (ex == null) {
                    logger.info("Published event [{}] to topic [{}] partition [{}] offset [{}]",
                            event.getId(),
                            result.getRecordMetadata().topic(),
                            result.getRecordMetadata().partition(),
                            result.getRecordMetadata().offset());
                } else {
                    logger.error("Failed to publish event [{}]: {}", event.getId(), ex.getMessage(), ex);
                }
            });
        } catch (JsonProcessingException e) {
            logger.error("Failed to serialize event: {}", e.getMessage(), e);
            throw new RuntimeException("Event serialization failed", e);
        }
    }

    public void publishNotification(String key, String message) {
        CompletableFuture<SendResult<String, String>> future =
                kafkaTemplate.send(NOTIFICATIONS_TOPIC, key, message);

        future.whenComplete((result, ex) -> {
            if (ex == null) {
                logger.info("Published notification to topic [{}] partition [{}] offset [{}]",
                        result.getRecordMetadata().topic(),
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            } else {
                logger.error("Failed to publish notification: {}", ex.getMessage(), ex);
            }
        });
    }

    public void publishAuditLog(String key, String auditMessage) {
        CompletableFuture<SendResult<String, String>> future =
                kafkaTemplate.send(AUDIT_TOPIC, key, auditMessage);

        future.whenComplete((result, ex) -> {
            if (ex == null) {
                logger.info("Published audit log to topic [{}] partition [{}] offset [{}]",
                        result.getRecordMetadata().topic(),
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            } else {
                logger.error("Failed to publish audit log: {}", ex.getMessage(), ex);
            }
        });
    }
}

