package com.eventplatform.consumer;

import com.eventplatform.model.Event;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.stereotype.Service;

@Service
public class EventConsumer {

    private static final Logger logger = LoggerFactory.getLogger(EventConsumer.class);
    private final ObjectMapper objectMapper;

    public EventConsumer() {
        this.objectMapper = new ObjectMapper();
        this.objectMapper.registerModule(new JavaTimeModule());
    }

    @KafkaListener(
            topics = "events-topic",
            groupId = "${kafka.consumer.group-id}",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeEvent(ConsumerRecord<String, String> record, Acknowledgment acknowledgment) {
        try {
            logger.info("Received event from topic [{}] partition [{}] offset [{}] key [{}]",
                    record.topic(), record.partition(), record.offset(), record.key());

            Event event = objectMapper.readValue(record.value(), Event.class);
            processEvent(event);

            acknowledgment.acknowledge();
            logger.info("Successfully processed and acknowledged event [{}]", event.getId());
        } catch (Exception e) {
            logger.error("Error processing event from partition [{}] offset [{}]: {}",
                    record.partition(), record.offset(), e.getMessage(), e);
            // In production, consider sending to a dead-letter topic
        }
    }

    @KafkaListener(
            topics = "notifications-topic",
            groupId = "${kafka.consumer.group-id}",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeNotification(ConsumerRecord<String, String> record, Acknowledgment acknowledgment) {
        try {
            logger.info("Received notification from topic [{}] partition [{}] offset [{}] key [{}]",
                    record.topic(), record.partition(), record.offset(), record.key());

            processNotification(record.key(), record.value());

            acknowledgment.acknowledge();
            logger.info("Successfully processed notification with key [{}]", record.key());
        } catch (Exception e) {
            logger.error("Error processing notification from partition [{}] offset [{}]: {}",
                    record.partition(), record.offset(), e.getMessage(), e);
        }
    }

    @KafkaListener(
            topics = "audit-topic",
            groupId = "${kafka.consumer.group-id}",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeAuditLog(ConsumerRecord<String, String> record, Acknowledgment acknowledgment) {
        try {
            logger.info("Received audit log from topic [{}] partition [{}] offset [{}] key [{}]",
                    record.topic(), record.partition(), record.offset(), record.key());

            processAuditLog(record.key(), record.value());

            acknowledgment.acknowledge();
            logger.info("Successfully processed audit log with key [{}]", record.key());
        } catch (Exception e) {
            logger.error("Error processing audit log from partition [{}] offset [{}]: {}",
                    record.partition(), record.offset(), e.getMessage(), e);
        }
    }

    private void processEvent(Event event) {
        logger.info("Processing event: type={}, source={}, id={}",
                event.getType(), event.getSource(), event.getId());
        // Business logic for event processing
    }

    private void processNotification(String key, String message) {
        logger.info("Processing notification: key={}", key);
        // Business logic for notification processing
    }

    private void processAuditLog(String key, String message) {
        logger.info("Processing audit log: key={}", key);
        // Business logic for audit log processing
    }
}

