package com.eventplatform.controller;

import com.eventplatform.model.Event;
import com.eventplatform.producer.EventProducer;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducer eventProducer;

    public EventController(EventProducer eventProducer) {
        this.eventProducer = eventProducer;
    }

    @PostMapping
    public ResponseEntity<Map<String, String>> publishEvent(@RequestBody Event event) {
        eventProducer.publishEvent(event);
        return ResponseEntity.status(HttpStatus.ACCEPTED)
                .body(Map.of("status", "accepted", "eventId", event.getId()));
    }

    @PostMapping("/notifications")
    public ResponseEntity<Map<String, String>> publishNotification(
            @RequestParam String key,
            @RequestBody String message) {
        eventProducer.publishNotification(key, message);
        return ResponseEntity.status(HttpStatus.ACCEPTED)
                .body(Map.of("status", "accepted", "key", key));
    }

    @PostMapping("/audit")
    public ResponseEntity<Map<String, String>> publishAuditLog(
            @RequestParam String key,
            @RequestBody String message) {
        eventProducer.publishAuditLog(key, message);
        return ResponseEntity.status(HttpStatus.ACCEPTED)
                .body(Map.of("status", "accepted", "key", key));
    }
}

